text:
body {
  @if config.$css--body == true {
    background-color: custom-property.get-var('background', #ffffff);
    color: custom-property.get-var('text-primary', #161616);
  }

  line-height: 1;
}

@container (width <= #{3 * $min-inline-button-size}) {
  .#{$prefix}--btn-set__fluid-inner#{has-n-children(1)} .#{$prefix}--btn {
    flex: 1 1 100%;
    max-inline-size: none;
  }
}

th:not(.#{$prefix}--table-column-checkbox):not(
    .#{$prefix}--table-column-menu
  ):not(.#{$prefix}--table-expand):not(.#{$prefix}--table-column-icon),
td:not(.#{$prefix}--table-column-checkbox):not(
    .#{$prefix}--table-column-menu
  ):not(.#{$prefix}--table-expand):not(.#{$prefix}--table-column-icon) {
  min-inline-size: $min-width;
}

@media screen and (min-width: 40em) and (max-width: 76.5em) {
  order: 3;
  display: flex;
  margin-left: 1rem;
}

@media screen and (min-width: 40em) and (max-width: 76.5em) {
  order: 2;
  display: flex;
  margin-right: 1rem;
}

@media screen and (min-width: 40em) and (max-width: 76.5em) {
  display: flex;
  flex: 1 0 auto;
  order: 1;
  width: 100%;
  justify-content: center;
}

&:hover,
  &:focus {
    color: $badge-link-hover-color;
    text-decoration: none;
    cursor: pointer;
  }

a.label {
  &:hover,
  &:focus {
    color: $label-link-hover-color;
    text-decoration: none;
    cursor: pointer;
  }
}

&:hover,
  &:focus {
    color: $label-link-hover-color;
    text-decoration: none;
    cursor: pointer;
  }

@-webkit-keyframes progress-bar-stripes {
  from  { background-position: 40px 0; }
  to    { background-position: 0 0; }
}

// Spec and IE10+
@keyframes progress-bar-stripes {
  from  { background-position: 40px 0; }
  to    { background-position: 0 0; }
}

@keyframes progress-bar-stripes {
  from  { background-position: 40px 0; }
  to    { background-position: 0 0; }
}

// Variations
// -------------------------

.progress-bar-success {
  @include progress-bar-variant($progress-bar-success-bg);
}

&:focus,
  &.focus {
    color: $color;
    background-color: darken($background, 10%);
    border-color: darken($border, 25%);
  }

&:hover {
  color: $color;
  background-color: darken($background, 10%);
  border-color: darken($border, 12%);
}

&:hover,
    &:focus,
    &.focus {
      color: $color;
      background-color: darken($background, 17%);
      border-color: darken($border, 25%);
    }

&:hover,
    &:focus,
    &.focus {
      background-color: $background;
      border-color: $border;
    }

@mixin container-fixed($gutter: $grid-gutter-width) {
  padding-right: ceil(math.div($gutter, 2));
  padding-left: floor(math.div($gutter, 2));
  margin-right: auto;
  margin-left: auto;
  @include clearfix;
}

@mixin make-row($gutter: $grid-gutter-width) {
  margin-right: floor(math.div($gutter, -2));
  margin-left: ceil(math.div($gutter, -2));
  @include clearfix;
}

> .bi {
  flex-shrink: 0;
  width: $icon-link-icon-size;
  height: $icon-link-icon-size;
  fill: currentcolor;
  @include transition($icon-link-icon-transition);
}

&:hover,
  &:focus-visible {
    > .bi {
      transform: var(--#{$prefix}icon-link-transform, $icon-link-icon-transform);
    }
  }

//
// Visually hidden
//

.visually-hidden,
.visually-hidden-focusable:not(:focus):not(:focus-within) {
  @include visually-hidden();
}

@if $value != null {
  @if $value == none or $value == initial or $value == inherit or $value == unset {
    $has-single-value: true;
    $single-value: $value;
  } @else {
    $result: append($result, $value, "comma");
  }
}

@if $value == none or $value == initial or $value == inherit or $value == unset {
  $has-single-value: true;
  $single-value: $value;
}

@mixin deprecate($name, $deprecate-version, $remove-version, $ignore-warning: false) {
  @if ($enable-deprecation-messages != false and $ignore-warning != true) {
    @warn "#{$name} has been deprecated as of #{$deprecate-version}. It will be removed entirely in #{$remove-version}.";
  }
}

@if ($enable-deprecation-messages != false and $ignore-warning != true) {
  @warn "#{$name} has been deprecated as of #{$deprecate-version}. It will be removed entirely in #{$remove-version}.";
}

@if length($transition) > 1 {
  @each $value in $transition {
    @if $value == null or $value == none {
      @warn "The keyword 'none' or 'null' must be used as a single argument.";
    }
  }
}

@each $value in $transition {
  @if $value == null or $value == none {
    @warn "The keyword 'none' or 'null' must be used as a single argument.";
  }
}

@if $value == null or $value == none {
  @warn "The keyword 'none' or 'null' must be used as a single argument.";
}

&:focus,
  &:hover,
  :hover > &,
  :target > & {
    color: $link-color;
    text-decoration: none;
    opacity: 1;
  }
